// friday13.cs — Friday the 13th explorer (proleptic Gregorian calendar)

// 1. Find the earliest Friday the 13th from 0001-01-01
var date = new DateTime(1, 1, 13); // start on the 13th of Jan 0001
while (date.DayOfWeek != DayOfWeek.Friday)
    date = date.AddMonths(1);

Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date.DayOfWeek})");

// 2. Count Friday the 13ths in one full 400-year Gregorian cycle (0001-01-13 .. 0400-12-13)
int count = 0;
var d = new DateTime(1, 1, 13);
var end = new DateTime(400, 12, 31);
while (d <= end)
{
    if (d.DayOfWeek == DayOfWeek.Friday)
        count++;
    d = d.AddMonths(1);
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");

// 3. Breakdown by day-of-week for the 13th (fun bonus)
Console.WriteLine("\n--- 13th-of-month distribution over 400 years ---");
var tally = new int[7];
d = new DateTime(1, 1, 13);
while (d <= end)
{
    tally[(int)d.DayOfWeek]++;
    d = d.AddMonths(1);
}
foreach (DayOfWeek dow in Enum.GetValues<DayOfWeek>())
    Console.WriteLine($"  {dow,-10} {tally[(int)dow],4}");

